import (
    "context"

    metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
    "k8s.io/apimachinery/pkg/runtime"
    "k8s.io/apimachinery/pkg/runtime/schema"
    "k8s.io/apimachinery/pkg/runtime/serializer"
    rest "k8s.io/client-go/rest"
)

// Widget types
type Widget struct {
    metav1.TypeMeta   `json:",inline"`
    metav1.ObjectMeta `json:"metadata,omitempty"`
    Spec   WidgetSpec   `json:"spec,omitempty"`
    Status WidgetStatus `json:"status,omitempty"`
}

type WidgetSpec struct {
    // Widget-specific fields
}

type WidgetStatus struct {
    // Widget-specific status fields
}

type WidgetList struct {
    metav1.TypeMeta `json:",inline"`
    metav1.ListMeta `json:"metadata,omitempty"`
    Items []Widget `json:"items"`
}

// Scheme setup
var (
    SchemeGroupVersion = schema.GroupVersion{Group: "example.com", Version: "v1"}
    SchemeBuilder      = runtime.NewSchemeBuilder(addToScheme)
    AddToScheme        = SchemeBuilder.AddToScheme
    Scheme             = runtime.NewScheme()
    Codecs             serializer.CodecFactory
    ParameterCodec     runtime.ParameterCodec
)

func init() {
    AddToScheme(Scheme)
    Codecs = serializer.NewCodecFactory(Scheme)
    ParameterCodec = runtime.NewParameterCodec(Scheme)
}

func addToScheme(scheme *runtime.Scheme) error {
    scheme.AddKnownTypes(SchemeGroupVersion,
        &Widget{},
        &WidgetList{},
    )
    metav1.AddToGroupVersion(scheme, SchemeGroupVersion)
    return nil
}

// WidgetsGetter has a method to return a WidgetInterface.
type WidgetsGetter interface {
    Widgets(namespace string) WidgetInterface
}

// WidgetInterface has methods to work with Widget resources.
type WidgetInterface interface {
    Create(ctx context.Context, widget *Widget, opts metav1.CreateOptions) (*Widget, error)
    Get(ctx context.Context, name string, opts metav1.GetOptions) (*Widget, error)
    List(ctx context.Context, opts metav1.ListOptions) (*WidgetList, error)
    Delete(ctx context.Context, name string, opts metav1.DeleteOptions) error
}

// widgets implements WidgetInterface
type widgets struct {
    client    rest.Interface
    namespace string
}

// ExampleV1Client is used to interact with the example.com/v1 API group.
type ExampleV1Client struct {
    restClient rest.Interface
}

// Widgets returns a WidgetInterface for the given namespace.
func (c *ExampleV1Client) Widgets(namespace string) WidgetInterface {
    return newWidgets(c, namespace)
}

// RESTClient returns the underlying REST client.
func (c *ExampleV1Client) RESTClient() rest.Interface {
    if c == nil {
        return nil
    }
    return c.restClient
}

// NewForConfig creates a new ExampleV1Client for the given config.
func NewForConfig(c *rest.Config) (*ExampleV1Client, error) {
    config := *c
    if err := setConfigDefaults(&config); err != nil {
        return nil, err
    }
    httpClient, err := rest.HTTPClientFor(&config)
    if err != nil {
        return nil, err
    }
    return NewForConfigAndClient(&config, httpClient)
}

// NewForConfigAndClient creates a new ExampleV1Client for the given config and http client.
func NewForConfigAndClient(c *rest.Config, h *http.Client) (*ExampleV1Client, error) {
    config := *c
    if err := setConfigDefaults(&config); err != nil {
        return nil, err
    }
    client, err := rest.RESTClientForConfigAndClient(&config, h)
    if err != nil {
        return nil, err
    }
    return &ExampleV1Client{client}, nil
}

// New creates a new ExampleV1Client for the given RESTClient.
func New(c rest.Interface) *ExampleV1Client {
    return &ExampleV1Client{c}
}

func setConfigDefaults(config *rest.Config) error {
    gv := SchemeGroupVersion
    config.GroupVersion = &gv
    config.APIPath = "/apis"
    config.NegotiatedSerializer = rest.CodecFactoryForGeneratedClient(Scheme, Codecs).WithoutConversion()
    if config.UserAgent == "" {
        config.UserAgent = rest.DefaultKubernetesUserAgent()
    }
    return nil
}

// newWidgets returns a widgets client.
func newWidgets(c *ExampleV1Client, namespace string) *widgets {
    return &widgets{
        client:    c.RESTClient(),
        namespace: namespace,
    }
}

// Create takes the representation of a widget and creates it.
func (c *widgets) Create(ctx context.Context, widget *Widget, opts metav1.CreateOptions) (*Widget, error) {
    result := &Widget{}
    err := c.client.Post().
        Namespace(c.namespace).
        Resource("widgets").
        VersionedParams(&opts, ParameterCodec).
        Body(widget).
        Do(ctx).
        Into(result)
    return result, err
}

// Get takes name of the widget, and returns the corresponding widget object, and an error if there is any.
func (c *widgets) Get(ctx context.Context, name string, opts metav1.GetOptions) (*Widget, error) {
    result := &Widget{}
    err := c.client.Get().
        Namespace(c.namespace).
        Resource("widgets").
        Name(name).
        VersionedParams(&opts, ParameterCodec).
        Do(ctx).
        Into(result)
    return result, err
}

// List takes label and field selectors, and returns the list of Widgets that match those selectors.
func (c *widgets) List(ctx context.Context, opts metav1.ListOptions) (*WidgetList, error) {
    result := &WidgetList{}
    err := c.client.Get().
        Namespace(c.namespace).
        Resource("widgets").
        VersionedParams(&opts, ParameterCodec).
        Do(ctx).
        Into(result)
    return result, err
}

// Delete takes name of the widget and deletes it. Returns an error if one occurs.
func (c *widgets) Delete(ctx context.Context, name string, opts metav1.DeleteOptions) error {
    return c.client.Delete().
        Namespace(c.namespace).
        Resource("widgets").
        Name(name).
        Body(&opts).
        Do(ctx).
        Error()
}
